#include <imgui.h>

void DrawAssetDropExample() {
    static const char* assets[] = {
        "Ship.mesh",
        "Crate.mesh",
        "SunLight.entity",
        "SmokeTrail.vfx"
    };
    static int active_asset = 0;

    ImGui::Begin("Asset Browser");
    ImGui::Text("اسحب أصلاً من القائمة إلى منطقة العرض.");
    ImGui::Separator();

    for (int i = 0; i < IM_ARRAYSIZE(assets); ++i) {
        ImGui::Selectable(assets[i], active_asset == i);
        if (ImGui::BeginDragDropSource()) {
            ImGui::SetDragDropPayload("ASSET_INDEX", &i, sizeof(int));
            ImGui::Text("المصدر: %s", assets[i]);
            ImGui::Text("نوع البيانات: ASSET_INDEX");
            ImGui::EndDragDropSource();
        }
    }
    ImGui::End();

    ImGui::Begin("Viewport Target");
    ImGui::Text("الهدف: إسقاط أصل فوق هذه المنطقة.");
    ImGui::Text("الأصل النشط حالياً: %s", assets[active_asset]);
    ImGui::Spacing();

    ImGui::InvisibleButton("viewport_target", ImVec2(340.0f, 200.0f));
    if (ImGui::IsItemHovered()) {
        ImGui::SetTooltip("حرر المؤشر هنا لتغيير الأصل المعروض.");
    }

    if (ImGui::BeginDragDropTarget()) {
        if (const ImGuiPayload* payload = ImGui::AcceptDragDropPayload("ASSET_INDEX")) {
            active_asset = *(const int*)payload->Data;
        }
        ImGui::EndDragDropTarget();
    }

    ImGui::Text("بعد الإفلات: يعرض Viewport الأصل المسقط.");
    ImGui::End();
}

