#include <imgui.h>
#include <utility>

void DrawInventoryDropExample() {
    static const char* slots[8] = {
        "Sword", "Potion", "Shield", "",
        "Bow", "", "Torch", "Key"
    };

    auto swap_slots = [&](int source_slot, int target_slot) {
        std::swap(slots[source_slot], slots[target_slot]);
    };

    ImGui::Begin("Inventory");
    ImGui::Text("اسحب عنصراً من Slot إلى Slot آخر.");
    ImGui::Separator();

    for (int slot = 0; slot < 8; ++slot) {
        if (slot > 0 && slot % 4 != 0) {
            ImGui::SameLine();
        }

        const char* label = slots[slot][0] ? slots[slot] : "[Empty]";
        ImGui::Button(label, ImVec2(84.0f, 84.0f));

        if (slots[slot][0] && ImGui::BeginDragDropSource()) {
            ImGui::SetDragDropPayload("INVENTORY_SLOT", &slot, sizeof(int));
            ImGui::Text("المصدر: slot %d", slot);
            ImGui::Text("العنصر: %s", slots[slot]);
            ImGui::EndDragDropSource();
        }

        if (ImGui::BeginDragDropTarget()) {
            if (const ImGuiPayload* payload = ImGui::AcceptDragDropPayload("INVENTORY_SLOT")) {
                const int source_slot = *(const int*)payload->Data;
                swap_slots(source_slot, slot);
            }
            ImGui::EndDragDropTarget();
        }
    }

    ImGui::Separator();
    ImGui::Text("بعد الإفلات: تتبدل محتويات الخانات أو ينتقل العنصر إلى الخانة الفارغة.");
    ImGui::End();
}

