#include <imgui.h>
#include <cstring>

void DrawColorPayloadExample() {
    static float accent_rgba[4] = {0.19f, 0.55f, 0.92f, 1.0f};
    static float material_rgba[4] = {0.36f, 0.39f, 0.44f, 1.0f};
    static const char* material_tag = "Default";
    static const char* tags[] = {"Metal", "Glass", "UI Accent"};

    ImGui::Begin("Color Sources");
    ImGui::ColorButton("Accent", ImVec4(accent_rgba[0], accent_rgba[1], accent_rgba[2], accent_rgba[3]));
    if (ImGui::BeginDragDropSource()) {
        ImGui::SetDragDropPayload("COLOR4", accent_rgba, sizeof(float) * 4);
        ImGui::Text("المصدر: لون RGBA");
        ImGui::EndDragDropSource();
    }

    for (int i = 0; i < IM_ARRAYSIZE(tags); ++i) {
        ImGui::Selectable(tags[i]);
        if (ImGui::BeginDragDropSource()) {
            ImGui::SetDragDropPayload("MATERIAL_TAG", tags[i], (int)strlen(tags[i]) + 1);
            ImGui::Text("المصدر: %s", tags[i]);
            ImGui::EndDragDropSource();
        }
    }
    ImGui::End();

    ImGui::Begin("Material Field");
    ImGui::Text("الهدف: حقل مادة يستقبل لوناً أو وسماً.");
    ImGui::ColorButton("Preview", ImVec4(material_rgba[0], material_rgba[1], material_rgba[2], material_rgba[3]));
    ImGui::Text("Current Tag: %s", material_tag);
    ImGui::InvisibleButton("material_target", ImVec2(260.0f, 90.0f));

    if (ImGui::BeginDragDropTarget()) {
        if (const ImGuiPayload* payload = ImGui::AcceptDragDropPayload("COLOR4")) {
            std::memcpy(material_rgba, payload->Data, sizeof(float) * 4);
        }
        if (const ImGuiPayload* payload = ImGui::AcceptDragDropPayload("MATERIAL_TAG")) {
            material_tag = (const char*)payload->Data;
        }
        ImGui::EndDragDropTarget();
    }
    ImGui::Text("بعد الإفلات: تتغير المعاينة أو الوسم بحسب نوع البيانات.");
    ImGui::End();
}

