#include <imgui.h>

struct SceneNode {
    int id;
    const char* label;
    int parent;
};

void DrawHierarchyReorderExample() {
    static SceneNode nodes[] = {
        {1, "Scene", 0},
        {2, "Camera", 1},
        {3, "Lights", 1},
        {4, "Meshes", 1},
        {5, "Player", 4}
    };

    auto reparent_node = [&](int source_id, int target_id) {
        for (SceneNode& node : nodes) {
            if (node.id == source_id && source_id != target_id) {
                node.parent = target_id;
            }
        }
    };

    ImGui::Begin("Scene Tree");
    ImGui::Text("اسحب عقدة وأفلِتها فوق عقدة أخرى لتغيير الأب الحالي.");
    ImGui::Separator();

    for (SceneNode& node : nodes) {
        ImGuiTreeNodeFlags flags = ImGuiTreeNodeFlags_OpenOnArrow;
        const bool opened = ImGui::TreeNodeEx(node.label, flags);

        if (ImGui::BeginDragDropSource()) {
            ImGui::SetDragDropPayload("SCENE_NODE", &node.id, sizeof(int));
            ImGui::Text("المصدر: %s", node.label);
            ImGui::Text("نوع البيانات: SCENE_NODE");
            ImGui::EndDragDropSource();
        }

        if (ImGui::BeginDragDropTarget()) {
            if (const ImGuiPayload* payload = ImGui::AcceptDragDropPayload("SCENE_NODE")) {
                const int source_id = *(const int*)payload->Data;
                reparent_node(source_id, node.id);
            }
            ImGui::EndDragDropTarget();
        }

        if (opened) {
            ImGui::Text("Node ID: %d", node.id);
            ImGui::Text("Parent ID: %d", node.parent);
            ImGui::TreePop();
        }
    }

    ImGui::End();
}
